#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {
        if (preorder.empty()) return NULL;
        TreeNode* root = new TreeNode(preorder[0]);
        int idx = find(inorder.begin(), inorder.end(), preorder[0]) - inorder.begin();
        vector<int> left_preorder(preorder.begin() + 1, preorder.begin() + idx + 1);
        vector<int> left_inorder(inorder.begin(), inorder.begin() + idx);
        vector<int> right_preorder(preorder.begin() + idx + 1, preorder.end());
        vector<int> right_inorder(inorder.begin() + idx + 1, inorder.end());
        root->left = buildTree(left_preorder, left_inorder);
        root->right = buildTree(right_preorder, right_inorder);
        return root;
    }
    vector<int> preorderTraversal(TreeNode* root) {
        if (!root) return {};
        vector<int> res = {root->val};
        auto left = preorderTraversal(root->left);
        auto right = preorderTraversal(root->right);
        res.insert(res.end(), left.begin(), left.end());
        res.insert(res.end(), right.begin(), right.end());
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> preorder(n);
    for (int i = 0; i < n; i++) cin >> preorder[i];
    int _;
    if (!(cin >> _)) return 0;
    vector<int> inorder(n);
    for (int i = 0; i < n; i++) cin >> inorder[i];
    Solution sol;
    TreeNode* root = sol.buildTree(preorder, inorder);
    auto res = sol.preorderTraversal(root);
    for (int i = 0; i < res.size(); i++) {
        cout << res[i] << (i == res.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
